function MortgageCalc() {
  const [principal, setPrincipal] = React.useState(400000);
  const [rate, setRate] = React.useState(6.5);
  const [years, setYears] = React.useState(30);

  const r = rate / 100 / 12;
  const n = years * 12;
  const monthly = principal && rate ? (principal * r * Math.pow(1 + r, n)) / (Math.pow(1 + r, n) - 1) : 0;
  const totalCost = monthly * n;
  const totalInterest = totalCost - principal;

  return (
    <div style={{ fontFamily: 'system-ui, sans-serif', padding: 16, background: '#ffffff', borderRadius: 12, height: '100%', display: 'flex', flexDirection: 'column', color: '#1e293b' }}>
      <h2 style={{ margin: '0 0 16px', fontSize: 18 }}>Mortgage Calculator</h2>
      <label style={{ fontSize: 13, marginBottom: 4, fontWeight: 500 }}>Loan Amount</label>
      <input type="number" value={principal} onChange={e => setPrincipal(Number(e.target.value))} style={{ marginBottom: 12, padding: 8, borderRadius: 6, border: '1px solid #cbd5e1', fontSize: 14 }} />
      <label style={{ fontSize: 13, marginBottom: 4, fontWeight: 500 }}>Interest Rate %</label>
      <input type="number" step="0.1" value={rate} onChange={e => setRate(Number(e.target.value))} style={{ marginBottom: 12, padding: 8, borderRadius: 6, border: '1px solid #cbd5e1', fontSize: 14 }} />
      <label style={{ fontSize: 13, marginBottom: 4, fontWeight: 500 }}>Years</label>
      <input type="number" value={years} onChange={e => setYears(Number(e.target.value))} style={{ marginBottom: 16, padding: 8, borderRadius: 6, border: '1px solid #cbd5e1', fontSize: 14 }} />
      <div style={{ background: '#f0fdf4', borderRadius: 8, padding: 12, marginTop: 'auto' }}>
        <div style={{ fontSize: 13, color: '#166534' }}>Monthly Payment</div>
        <div style={{ fontSize: 28, fontWeight: 700, color: '#059669' }}>${monthly.toFixed(2)}</div>
        <div style={{ fontSize: 12, color: '#64748b', marginTop: 4 }}>Total interest: ${totalInterest.toLocaleString(undefined, {maximumFractionDigits: 2})}</div>
      </div>
    </div>
  );
}
render(<MortgageCalc/>);
